section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/testing-js-ts-frontend.json",
  "type": "object",
  "required": [
    "component_file",
    "runner",
    "query_strategy_ok",
    "explicit_imports_or_globals",
    "mock_api_matches_runner",
    "uses_user_event",
    "axe_assertion"
  ],
  "properties": {
    "component_file": {
      "type": "string",
      "pattern": "^.+\\.(tsx|ts|jsx|js|vue|svelte)$"
    },
    "runner": {
      "enum": [
        "vitest",
        "jest"
      ]
    },
    "query_strategy_ok": {
      "type": "boolean",
      "const": true
    },
    "explicit_imports_or_globals": {
      "type": "boolean",
      "const": true
    },
    "mock_api_matches_runner": {
      "type": "boolean",
      "const": true
    },
    "uses_user_event": {
      "type": "boolean",
      "const": true
    },
    "axe_assertion": {
      "type": "boolean",
      "const": true
    },
    "snapshot_lines": {
      "type": "integer",
      "maximum": 30
    }
  },
  "additionalProperties": false
}
